// Copyright 2011 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.package packetimport ("io""io/ioutil""strings")// UserId contains text that is intended to represent the name and email// address of the key holder. See RFC 4880, section 5.11. By convention, this// takes the form "Full Name (Comment) <email@example.com>"type UserId struct {Id string // By convention, this takes the form "Full Name (Comment) <email@example.com>" which is split out in the fields below.Name, Comment, Email string}InvalidCharacters(s string) bool {for _, c := range s {switch c {case '(', ')', '<', '>', 0:return true}}return false}// NewUserId returns a UserId or nil if any of the arguments contain invalid// characters. The invalid characters are '\x00', '(', ')', '<' and '>'UserId(name, comment, email string) *UserId {// RFC 4880 doesn't deal with the structure of userid strings; the// name, comment and email form is just a convention. However, there's// no convention about escaping the metacharacters and GPG just refuses// to create user ids where, say, the name contains a '('. We mirror// this behaviour.if hasInvalidCharacters(name) || hasInvalidCharacters(comment) || hasInvalidCharacters(email) {return nil}uid := new(UserId)uid.Name, uid.Comment, uid.Email = name, comment, emailuid.Id = nameif len(comment) > 0 {if len(uid.Id) > 0 {uid.Id += " "}uid.Id += "("uid.Id += commentuid.Id += ")"}if len(email) > 0 {if len(uid.Id) > 0 {uid.Id += " "}uid.Id += "<"uid.Id += emailuid.Id += ">"}return uid}d *UserId) parse(r io.Reader) (err error) {// RFC 4880, section 5.11b, err := ioutil.ReadAll(r)if err != nil {return}uid.Id = string(b)uid.Name, uid.Comment, uid.Email = parseUserId(uid.Id)return}// Serialize marshals uid to w in the form of an OpenPGP packet, including// header.d *UserId) Serialize(w io.Writer) error {err := serializeHeader(w, packetTypeUserId, len(uid.Id))if err != nil {return err}_, err = w.Write([]byte(uid.Id))return err}// parseUserId extracts the name, comment and email from a user id string that// is formatted as "Full Name (Comment) <email@example.com>".seUserId(id string) (name, comment, email string) {var n, c, e struct {start, end int}var state intfor offset, rune := range id {switch state {case 0:// Entering namen.start = offsetstate = 1fallthroughcase 1:// In nameif rune == '(' {state = 2n.end = offset} else if rune == '<' {state = 5n.end = offset}case 2:// Entering commentc.start = offsetstate = 3fallthroughcase 3:// In commentif rune == ')' {state = 4c.end = offset}case 4:// Between comment and emailif rune == '<' {state = 5}case 5:// Entering emaile.start = offsetstate = 6fallthroughcase 6:// In emailif rune == '>' {state = 7e.end = offset}default:// After email}}switch state {case 1:// ended in the namen.end = len(id)case 3:// ended in commentc.end = len(id)case 6:// ended in emaile.end = len(id)}name = strings.TrimSpace(id[n.start:n.end])comment = strings.TrimSpace(id[c.start:c.end])email = strings.TrimSpace(id[e.start:e.end])// RFC 2822 3.4: alternate simple form of a mailboxif email == "" && strings.ContainsRune(name, '@') {email = namename = ""}return}